    def _verify_message_signature(self, message: Dict[str, Any]) -> bool:
        """Verify HMAC signature of message if present"""
        if not self.hmac_secret:
            return True
        
        signature = message.get('signature', '')
        if not signature:
            logger.warning("Message missing signature")
            return False
        
        message_copy = message.copy()
        message_copy.pop('signature', None)
        
        canonical = json.dumps(message_copy, sort_keys=True)
        expected_signature = hmac.new(
            self.hmac_secret.encode(),
            canonical.encode(),
            hashlib.sha256
        ).hexdigest()
        
        return hmac.compare_digest(signature, expected_signature)
    
